import { SVG_NS } from '../shared/tokens/icons.js';
import { defineParts } from '../shared/definePart.js';

/** SVG namespace URI */
export const NS = SVG_NS;

/** Default color palette (8 colors) */
export const PALETTE = Object.freeze([
    'hsl(216,72%,56%)',  // blue
    'hsl(340,65%,55%)',  // pink
    'hsl(160,55%,45%)',  // teal
    'hsl(45,85%,55%)',   // amber
    'hsl(270,55%,55%)',  // purple
    'hsl(15,75%,55%)',   // orange
    'hsl(190,60%,45%)',  // cyan
    'hsl(100,50%,45%)',  // green
]);

/** Trading chart types that route to the trading renderer. */
export const TRADING_TYPES = Object.freeze(['candlestick', 'ohlc', 'heikin-ashi']);

/** Lite chart types that route to the lite renderer. */
export const LITE_TYPES = Object.freeze(['price-line', 'baseline']);

/** Default chart configuration */
export const DEFAULTS = Object.freeze({
    type: 'bar',
    labels: [],
    datasets: [],
    width: '100%',
    height: 300,
    animate: true,
    duration: 600,
    easing: 'ease-out',
    padding: { top: 20, right: 20, bottom: 40, left: 50 },
    grid: true,
    legend: true,
    tooltip: true,
    stacked: false,
    yMin: null,
    yMax: null,
    xMin: null,
    xMax: null,
    donutWidth: 0,
    smooth: false,
    showValues: false,
    onClick: null,
    onHover: null,
    renderContext: null,
    value: 0,
    min: null,
    max: null,
    segments: null,
    gaugeLabel: null,
    formatValue: null,
    nodes: [],
    links: [],

    // ── Trading-specific defaults ──
    // Pre-install feature modules for these types so type-switching is instant.
    // e.g. enableTypes: ['candlestick', 'ohlc', 'heikin-ashi', 'price-line']
    enableTypes: null,

    // Which side to render the price axis: 'left' or 'right'.
    priceAxis: 'left',

    // Whether to show the percentage-change axis on the opposite side.
    showPercentage: true,
});

/** Default padding values */
export const DEFAULT_PADDING = Object.freeze({ top: 20, right: 20, bottom: 40, left: 50 });

