/**
 * @fileoverview Chart events — centralised event binding (hover, click, tooltip).
 * @module module/Chart/events
 */

import { Elements } from '../../index.js';

/**
 * Bind mouseenter / mousemove / mouseleave / click events to a chart element.
 *
 * @param {Object} ctx  — chart context accessor (container, tooltip, config, css)
 * @param {SVGElement|HTMLElement} el — target element
 * @param {Object} info — data payload { datasetIndex, index, value, label, percent?, x?, y?, r? }
 */
export function bindHover(ctx, el, info) {
    const $el = new Elements(el);

    $el.on('mouseenter', () => {
        if (ctx.tooltip) {
            let html = `<strong>${info.label || ''}</strong>`;
            if (info.percent) html += ` — ${info.percent}`;
            html += `<br>${info.value}`;
            ctx.tooltip.html(html);
            ctx.tooltip.addClass('is-visible');
        }
        $el.css('opacity', '0.8');
        if (typeof ctx.config.onHover === 'function') {
            ctx.config.onHover(info);
        }
    });

    $el.on('mousemove', (e) => {
        if (ctx.tooltip) {
            const rect = ctx.container.getRect();
            ctx.tooltip.css({
                left: (e.clientX - rect.left + 12) + 'px',
                top: (e.clientY - rect.top - 8) + 'px',
            });
        }
    });

    $el.on('mouseleave', () => {
        if (ctx.tooltip) ctx.tooltip.removeClass('is-visible');
        $el.css('opacity', '');
    });

    $el.on('click', () => {
        if (typeof ctx.config.onClick === 'function') {
            ctx.config.onClick(info);
        }
    });

    $el.css('cursor', ctx.config.onClick ? 'pointer' : 'default');
}
