/**
 * @fileoverview Chart helpers — pure utility functions for scale, geometry,
 *               SVG element creation, and path interpolation.
 * @module module/Chart/helpers
 */

import { NS } from './constants.js';

/**
 * Create an SVG-namespaced element with attributes.
 * @param {string} tag — SVG tag name
 * @param {Object} [attrs] — attribute key/value pairs
 * @returns {SVGElement}
 */
export function svgEl(tag, attrs = {}) {
    const el = document.createElementNS(NS, tag);
    for (const [k, v] of Object.entries(attrs)) {
        if (v !== undefined && v !== null) el.setAttribute(k, v);
    }
    return el;
}

/**
 * Compute a "nice" scale for an axis (rounded min, max, and tick steps).
 * @param {number} min — data minimum
 * @param {number} max — data maximum
 * @param {number} [ticks=5] — desired number of ticks
 * @returns {{ min: number, max: number, step: number, steps: number[] }}
 */
export function niceScale(min, max, ticks = 5) {
    if (min === max) { min -= 1; max += 1; }
    const range = max - min;
    const rough = range / ticks;
    const mag = Math.pow(10, Math.floor(Math.log10(rough)));
    const residual = rough / mag;
    let nice;
    if (residual <= 1.5) nice = 1;
    else if (residual <= 3) nice = 2;
    else if (residual <= 7) nice = 5;
    else nice = 10;
    const step = nice * mag;
    const nMin = Math.floor(min / step) * step;
    const nMax = Math.ceil(max / step) * step;
    const steps = [];
    for (let v = nMin; v <= nMax + step * 0.01; v += step) {
        steps.push(Math.round(v * 1e10) / 1e10);
    }
    return { min: nMin, max: nMax, step, steps };
}

/**
 * Linear interpolation.
 * @param {number} a — start
 * @param {number} b — end
 * @param {number} t — 0–1 progress
 * @returns {number}
 */
export function lerp(a, b, t) { return a + (b - a) * t; }

/**
 * Convert polar to cartesian coordinates (for pie/radar/gauge).
 * @param {number} cx — center x
 * @param {number} cy — center y
 * @param {number} r — radius
 * @param {number} angleDeg — angle in degrees (0 = top)
 * @returns {{ x: number, y: number }}
 */
export function polarToCart(cx, cy, r, angleDeg) {
    const rad = (angleDeg - 90) * Math.PI / 180;
    return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
}

/**
 * Build a smooth SVG path using cardinal spline (Catmull-Rom → Bezier).
 * @param {Array<{x:number, y:number}>} points
 * @param {boolean} [closed=false]
 * @returns {string} SVG path d attribute
 */
export function smoothPath(points, closed = false) {
    if (points.length < 2) return '';
    if (points.length === 2) {
        return `M${points[0].x},${points[0].y}L${points[1].x},${points[1].y}`;
    }
    const tension = 0.15;
    let d = `M${points[0].x},${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
        const p0 = points[Math.max(0, i - 1)];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = points[Math.min(points.length - 1, i + 2)];
        const cp1x = p1.x + (p2.x - p0.x) * tension;
        const cp1y = p1.y + (p2.y - p0.y) * tension;
        const cp2x = p2.x - (p3.x - p1.x) * tension;
        const cp2y = p2.y - (p3.y - p1.y) * tension;
        d += `C${cp1x},${cp1y},${cp2x},${cp2y},${p2.x},${p2.y}`;
    }
    if (closed) d += 'Z';
    return d;
}

/**
 * Merge user config with defaults, ensuring padding sub-object merges correctly.
 * @param {Object} defaults — default config shape
 * @param {Object} defaultPadding — default padding sub-object
 * @param {Object} config — user-supplied config
 * @returns {Object}
 */
export function mergeConfig(defaults, defaultPadding, config) {
    return Object.assign({}, defaults, config, {
        padding: Object.assign({}, defaultPadding, config.padding || {}),
    });
}
